module RefModule(clk, reset, d, q);

    input  clk;  
    input  reset;  
    input  d;
    output  q;
  wire _tap_clk = clk & {1{1'b1}};

    reg   q; 

    always @(posedge clk)
          begin
            if (reset)
                q <= 0;
            else
                q <= d;
          end  

endmodule
